const MU_BLUE  = "#1C294D";   // Mercyhurst University blue (confirmed from official Lakers SVG)
const MASCOT_IMG = "data:image/png;base64,";

// ── CONFIG ───────────────────────────────────────────────────────────────────
const API_BASE = import.meta.env.VITE_API_URL || "";

