const MOCK_SEARCH = {
  total: 6,
  positive: [
    { post_text: "The new study lounge is actually fire, great vibes in there", likes: 203, timestamp: "2024-03-14T15:00:00Z", profanity_color: "green" },
    { post_text: "Shoutout to the barista at the campus coffee shop – you made my day", likes: 178, timestamp: "2024-03-13T10:22:00Z", profanity_color: "green" },
  ],
  neutral: [
    { post_text: "Has anyone used the study rooms on the 4th floor? Are they quiet?", likes: 44, timestamp: "2024-03-14T18:30:00Z", profanity_color: "green" },
    { post_text: "The campus bookstore finally restocked blue books", likes: 31, timestamp: "2024-03-15T11:00:00Z", profanity_color: "green" },
  ],
  negative: [
    { post_text: "Parking situation on campus is absolutely ridiculous", likes: 267, timestamp: "2024-03-15T08:45:00Z", profanity_color: "yellow" },
    { post_text: "Three fire alarms this week at 3am is not okay", likes: 199, timestamp: "2024-03-14T03:12:00Z", profanity_color: "green" },
  ],
};

// ── HELPERS ───────────────────────────────────────────────────────────────────
const profanityEmoji = (color) => ({ green: "🟢", yellow: "🟡", red: "🔴" }[color] ?? "🟢");
const sentimentColor = (s) => ({ positive: YY_GREEN, neutral: "#ffd166", negative: "#ff4d6d" }[s] ?? "#aaa");
const timeAgo = (iso) => {
  const diff = (Date.now() - new Date(iso)) / 1000;
  if (diff < 60)    return `${Math.floor(diff)}s ago`;
  if (diff < 3600)  return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`;
  return `${Math.floor(diff / 86400)}d ago`;
};
const apiFetch = async (path) => {
  const r = await fetch(`${API_BASE}${path}`);
  if (!r.ok) throw new Error(r.statusText);
  return r.json();
};

// ── POST CARD ─────────────────────────────────────────────────────────────────
function PostCard({ post, rank }) {
  return (
    <div
      style={{
        background: `rgba(28,41,77,0.3)`,
        border: `1px solid rgba(28,41,77,0.75)`,
        borderRadius: 14,
        padding: "16px 20px",
        display: "flex",
        gap: 14,
        alignItems: "flex-start",
        transition: "background 0.2s, border-color 0.2s",
        cursor: "default",
      }}
      onMouseEnter={e => {
        e.currentTarget.style.background = `rgba(28,41,77,0.6)`;
        e.currentTarget.style.borderColor = `${YY_GREEN}55`;
      }}
      onMouseLeave={e => {
        e.currentTarget.style.background = `rgba(28,41,77,0.3)`;
        e.currentTarget.style.borderColor = `rgba(28,41,77,0.75)`;
      }}
    >
      {rank !== undefined && (
        <div style={{
          fontFamily: "'Bebas Neue', cursive",
          fontSize: 28,
          color: rank === 0 ? YY_GREEN : "rgba(255,255,255,0.2)",
          lineHeight: 1,
          minWidth: 28,
          paddingTop: 2,
        }}>{rank + 1}</div>
      )}
      <div style={{ flex: 1 }}>
        <p style={{ margin: 0, color: "#dde8ff", fontSize: 14, lineHeight: 1.6, fontFamily: "'DM Sans', sans-serif" }}>
          {profanityEmoji(post.profanity_color)} {post.post_text}
        </p>
        <div style={{ display: "flex", gap: 12, marginTop: 8, alignItems: "center" }}>
          <span style={{ fontSize: 12, color: YY_GREEN, fontFamily: "monospace" }}>
            ▲ {post.likes.toLocaleString()}
          </span>
          <span style={{
            fontSize: 11,
            background: sentimentColor(post.sentiment) + "22",
            color: sentimentColor(post.sentiment),
            padding: "2px 8px",
            borderRadius: 20,
            fontFamily: "'DM Sans', sans-serif",
            textTransform: "capitalize",
          }}>{post.sentiment}</span>
          <span style={{ fontSize: 11, color: "rgba(255,255,255,0.3)", fontFamily: "monospace" }}>
            {timeAgo(post.timestamp)}
          </span>
        </div>
      </div>
    </div>
  );
}

// ── SEARCH TAB ────────────────────────────────────────────────────────────────
function SearchResultTab({ posts, sentiment, activeTab, setActiveTab, count }) {
  const isActive = activeTab === sentiment;
  const color = sentimentColor(sentiment);
  const labels = { positive: "Positive 😊", neutral: "Neutral 😐", negative: "Negative 😤" };

  return (
    <div>
      <button
        onClick={() => setActiveTab(isActive ? null : sentiment)}
        style={{
          width: "100%",
          background: isActive ? `rgba(28,41,77,0.65)` : `rgba(28,41,77,0.2)`,
          border: `1px solid ${isActive ? color + "66" : "rgba(28,41,77,0.85)"}`,
          borderRadius: isActive ? "12px 12px 0 0" : 12,
          padding: "14px 20px",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          cursor: "pointer",
          transition: "all 0.2s",
        }}
      >
        <span style={{ color: isActive ? color : "#bfd0ff", fontFamily: "'DM Sans', sans-serif", fontSize: 14, fontWeight: 600 }}>
          {labels[sentiment]}
        </span>
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <span style={{ background: color + "33", color, padding: "2px 10px", borderRadius: 20, fontSize: 12, fontFamily: "monospace" }}>
            {count} posts
          </span>
          <span style={{ color: isActive ? color : "rgba(255,255,255,0.3)", fontSize: 12 }}>
            {isActive ? "▲" : "▼"}
          </span>
        </div>
      </button>

      {isActive && (
        <div style={{
          background: "rgba(7,13,31,0.7)",
          border: `1px solid ${color + "33"}`,
          borderTop: "none",
          borderRadius: "0 0 12px 12px",
          padding: "12px 16px",
          display: "flex",
          flexDirection: "column",
          gap: 8,
          maxHeight: 360,
          overflowY: "auto",
        }}>
          {posts.length === 0
            ? <p style={{ color: "rgba(255,255,255,0.3)", fontSize: 13, fontFamily: "'DM Sans', sans-serif", textAlign: "center", margin: "20px 0" }}>No {sentiment} posts found.</p>
            : posts.map((p, i) => <PostCard key={i} post={{ ...p, sentiment }} />)
          }
        </div>
      )}
    </div>
  );
}

// ── TOOLTIP ───────────────────────────────────────────────────────────────────
function CustomTooltip({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background: MU_BLUE, border: `1px solid ${YY_GREEN}55`, borderRadius: 8, padding: "8px 14px" }}>
      <p style={{ margin: 0, color: "#c8d8ff", fontFamily: "monospace", fontSize: 12 }}>{label}</p>
      <p style={{ margin: 0, color: YY_GREEN, fontFamily: "monospace", fontSize: 13 }}>▲ {payload[0].value} posts</p>
    </div>
  );
}

// ── MAIN ──────────────────────────────────────────────────────────────────────
export default function YikHakd() {
  const [topPosts, setTopPosts]           = useState(MOCK_TOP_POSTS);
  const [activeTimes, setActiveTimes]     = useState(MOCK_ACTIVE_TIMES);
  const [query, setQuery]                 = useState("");
  const [searchResults, setSearchResults] = useState(null);
  const [searching, setSearching]         = useState(false);
  const [activeTab, setActiveTab]         = useState(null);
  const [lastUpdated, setLastUpdated]     = useState(new Date());
  const [usingMock, setUsingMock]         = useState(true);
  const searchRef = useRef(null);

  useEffect(() => {
    const load = async () => {
      try {
        const [posts, times] = await Promise.all([apiFetch("/top-posts?limit=5"), apiFetch("/active-times")]);
        setTopPosts(posts);
        setActiveTimes(times);
        setUsingMock(false);
        setLastUpdated(new Date());
      } catch {}
    };
    load();
    const id = setInterval(load, 60 * 60 * 1000);
    return () => clearInterval(id);
  }, []);

  const handleSearch = async () => {
    if (!query.trim()) return;
    setSearching(true);
    setSearchResults(null);
    setActiveTab(null);
    try {
      setSearchResults(await apiFetch(`/search?keyword=${encodeURIComponent(query)}`));
    } catch {
      setSearchResults(MOCK_SEARCH);
    } finally {
      setSearching(false);
      setTimeout(() => searchRef.current?.scrollIntoView({ behavior: "smooth" }), 100);
    }
  };

  const peakHour = activeTimes.reduce((a, b) => a.count > b.count ? a : b, activeTimes[0]);

  return (
    <div style={{ minHeight: "100vh", background: "#07101f", fontFamily: "'DM Sans', sans-serif", overflowX: "hidden" }}>

      {/* Background glow */}
      <div style={{
        position: "fixed", inset: 0, pointerEvents: "none", zIndex: 0,
        background: [
          `radial-gradient(ellipse 80% 50% at 50% -5%, ${MU_BLUE}ee 0%, transparent 65%)`,
          `radial-gradient(ellipse 45% 30% at 90% 90%, ${YY_GREEN}14 0%, transparent 55%)`,
        ].join(", "),
      }} />

      <div style={{ position: "relative", zIndex: 1, maxWidth: 720, margin: "0 auto", padding: "0 20px 80px" }}>

        {/* ── HERO ── */}
        <div style={{ textAlign: "center", paddingTop: 56, paddingBottom: 44 }}>

          {/* Logo */}
          <div style={{
            width: 78, height: 78, borderRadius: 22,
            background: `linear-gradient(145deg, ${MU_BLUE} 0%, #0b1530 100%)`,
            border: `2.5px solid ${YY_GREEN}`,
            margin: "0 auto 22px",
            display: "flex", alignItems: "center", justifyContent: "center",
            boxShadow: `0 0 32px ${YY_GREEN}55, 0 0 70px ${MU_BLUE}`,
          }}><img src={MASCOT_IMG} alt="Laker Mascot" style={{ width: "100%", height: "100%", objectFit: "cover", borderRadius: "50%" }} /></div>

          <h1 style={{
            fontFamily: "'Bebas Neue', cursive",
            fontSize: "clamp(52px, 12vw, 88px)",
            letterSpacing: 4,
            margin: 0,
            background: `linear-gradient(135deg, #ffffff 0%, #c8d8ff 40%, ${YY_GREEN} 100%)`,
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            lineHeight: 0.95,
          }}>YIK HAK'D</h1>

          <p style={{ color: "rgba(200,216,255,0.4)", fontSize: 13, marginTop: 10, letterSpacing: 2, textTransform: "uppercase", fontFamily: "monospace" }}>
            your campus, unfiltered
          </p>

          {usingMock && (
            <div style={{
              display: "block", marginTop: 10,
              background: "rgba(255,209,102,0.07)", border: "1px solid rgba(255,209,102,0.2)",
              borderRadius: 20, padding: "4px 14px", fontSize: 11, color: "#ffd166", fontFamily: "monospace",
            }}>⚠ demo mode – connect API at {API_BASE}</div>
          )}
        </div>

        {/* ── SEARCH ── */}
        <div style={{ marginBottom: 48 }}>
          <div style={{
            display: "flex",
            background: `rgba(28,41,77,0.35)`,
            border: `1.5px solid ${MU_BLUE}`,
            borderRadius: 50, overflow: "hidden",
            boxShadow: `0 0 28px ${MU_BLUE}88`,
            transition: "box-shadow 0.25s, border-color 0.25s",
          }}
          onFocus={e => { e.currentTarget.style.boxShadow = `0 0 36px ${YY_GREEN}44`; e.currentTarget.style.borderColor = YY_GREEN; }}
          onBlur={e => { e.currentTarget.style.boxShadow = `0 0 28px ${MU_BLUE}88`; e.currentTarget.style.borderColor = MU_BLUE; }}
          >
            <span style={{ padding: "0 0 0 20px", display: "flex", alignItems: "center", color: "rgba(255,255,255,0.25)", fontSize: 16 }}>🔍</span>
            <input
              value={query}
              onChange={e => setQuery(e.target.value)}
              onKeyDown={e => e.key === "Enter" && handleSearch()}
              placeholder="Search posts, topics, keywords…"
              style={{ flex: 1, background: "transparent", border: "none", outline: "none", color: "#dde8ff", fontSize: 15, padding: "16px 16px", fontFamily: "'DM Sans', sans-serif" }}
            />
            <button
              onClick={handleSearch}
              disabled={searching}
              style={{
                background: `linear-gradient(135deg, ${YY_GREEN} 0%, #3a8a2e 100%)`,
                border: "none", borderRadius: "0 50px 50px 0",
                color: "#fff", fontFamily: "'DM Sans', sans-serif",
                fontWeight: 700, fontSize: 14,
                padding: "0 28px", cursor: "pointer",
                opacity: searching ? 0.6 : 1, transition: "opacity 0.2s",
              }}
            >{searching ? "Searching…" : "Search"}</button>
          </div>
        </div>

        {/* ── RESULTS ── */}
        {searchResults && (
          <div ref={searchRef} style={{ marginBottom: 56 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <h2 style={{ fontFamily: "'Bebas Neue', cursive", fontSize: 26, color: "#dde8ff", margin: 0, letterSpacing: 2 }}>
                Results for "{query}"
              </h2>
              <span style={{ color: "rgba(255,255,255,0.3)", fontSize: 12, fontFamily: "monospace" }}>
                {searchResults.total} posts found
              </span>
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
              {["positive", "neutral", "negative"].map(s => (
                <SearchResultTab key={s} sentiment={s} posts={searchResults[s]} count={searchResults[s].length} activeTab={activeTab} setActiveTab={setActiveTab} />
              ))}
            </div>
          </div>
        )}

        {/* ── TOP 5 ── */}
        <section style={{ marginBottom: 56 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 18 }}>
            <h2 style={{ fontFamily: "'Bebas Neue', cursive", fontSize: 26, color: "#dde8ff", margin: 0, letterSpacing: 2 }}>
              🔥 Top Posts Right Now
            </h2>
            <span style={{ fontSize: 11, color: "rgba(255,255,255,0.25)", fontFamily: "monospace" }}>
              updated {timeAgo(lastUpdated.toISOString())}
            </span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {topPosts.map((p, i) => <PostCard key={i} post={p} rank={i} />)}
          </div>
        </section>

        {/* ── ACTIVE TIMES ── */}
        <section>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 18 }}>
            <h2 style={{ fontFamily: "'Bebas Neue', cursive", fontSize: 26, color: "#dde8ff", margin: 0, letterSpacing: 2 }}>
              📊 Most Active Times
            </h2>
            <span style={{
              background: `${YY_GREEN}18`, border: `1px solid ${YY_GREEN}44`,
              color: YY_GREEN, borderRadius: 20, padding: "2px 12px",
              fontSize: 11, fontFamily: "monospace",
            }}>Peak: {peakHour?.label}</span>
          </div>

          <div style={{
            background: `rgba(28,41,77,0.2)`,
            border: `1px solid rgba(28,41,77,0.85)`,
            borderRadius: 16, padding: "24px 12px 12px",
          }}>
            <ResponsiveContainer width="100%" height={180}>
              <BarChart data={activeTimes} margin={{ top: 0, right: 8, left: -20, bottom: 0 }} barCategoryGap="20%">
                <XAxis dataKey="label" tick={{ fill: "rgba(200,216,255,0.3)", fontSize: 10, fontFamily: "monospace" }} axisLine={false} tickLine={false} interval={2} />
                <YAxis tick={{ fill: "rgba(200,216,255,0.25)", fontSize: 10, fontFamily: "monospace" }} axisLine={false} tickLine={false} />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: "rgba(255,255,255,0.025)" }} />
                <Bar dataKey="count" radius={[4, 4, 0, 0]}>
                  {activeTimes.map((entry, i) => (
                    <Cell
                      key={i}
                      fill={
                        entry.hour === peakHour?.hour ? YY_GREEN
                        : entry.count > 80 ? MU_BLUE + "dd"
                        : MU_BLUE + "88"
                      }
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
            <p style={{ margin: "8px 0 0", color: "rgba(200,216,255,0.2)", fontSize: 11, textAlign: "center", fontFamily: "monospace" }}>
              posts by hour of day
            </p>
          </div>
        </section>

      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:wght@400;500;600;700&display=swap');
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: ${YY_GREEN}55; border-radius: 4px; }
      `}</style>
    </div>
  );
}
